    gCells(project,rid,'enemy').forEach(c=>
      enemies.push({id:'e_'+rid+'_'+c.idx,roomId:rid,x:c.x+TS/2-EW/2,y:c.y+TS/2-EH/2,w:EW,h:EH,vx:1.5,vy:0,onGround:false,health:1,invTimer:0,dir:1}));
